def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity < 0 or item < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        penalty = 0.0
        score = 0.0
        decay = 1.0
        extra = 0.0
        if ratio > 4:
            for k in range(1, 7):
                term = ((-1) ** k) * (ratio ** (k + 2)) / (k * k + 1)
                penalty += term
            for j in range(1, 5):
                decay *= np.exp(-j / (ratio + 1))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 5:
                score *= 3.5
            else:
                score *= 2.5
            priorities[i] = abs(score) * decay
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                score += sign * (ratio ** (x / 2)) / (x + 3)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 2))
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0.0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 2)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 3)
                else:
                    temp += (ratio ** p) / (p * 4)
            multiplier = 20 if ratio < 2.5 else 15
            if 2.8 < ratio <= 3:
                extra = 0.0
                for m in range(1, 10):
                    extra += (ratio ** (m / 2)) / (m + 2)
                temp += extra * 1.5
            score = abs(temp) * multiplier
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for n in range(1, 20):
                if n % 5 == 0:
                    temp_score += (ratio ** n) / (n * 7)
                elif n % 4 == 0:
                    temp_score -= (ratio ** n) / (n * 6)
                elif n % 3 == 0:
                    temp_score += (ratio ** n) / (n * 5)
                else:
                    temp_score -= (ratio ** n) / (n * 4)
            multiplier = 30 if ratio < 1.3 else 20 if ratio < 1.8 else 12
            if ratio > 1.7:
                extra_penalty = 0
                for q in range(1, 8):
                    extra_penalty += (ratio ** (q / 1.5)) / (q + 3)
                temp_score += extra_penalty * 3
            score = abs(temp_score) * multiplier
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0.0
            for r in range(1, 25):
                if r % 6 == 0:
                    temp_score += (ratio ** r) / (r * 8)
                elif r % 5 == 0:
                    temp_score -= (ratio ** r) / (r * 7)
                elif r % 4 == 0:
                    temp_score += (ratio ** r) / (r * 6)
                else:
                    temp_score -= (ratio ** r) / (r * 5)
            if ratio < 0.15:
                multiplier = 35
            elif ratio < 0.35:
                multiplier = 25
            elif ratio < 0.65:
                multiplier = 18
            elif ratio < 0.9:
                multiplier = 10
            else:
                multiplier = 7
            score = abs(temp_score) * multiplier
            if ratio > 0.8:
                extra_penalties = 0
                for s in range(1, 10):
                    extra_penalties += (ratio ** s) / (s + 2)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            priorities[i] = 0 if item == 0 else np.inf
        if priorities[i] != np.inf and capacity > 0:
            factor = 1.0
            for z in range(1, 5):
                factor *= (1 + z / (capacity + 1))
            priorities[i] *= factor
        elif capacity <= 0:
            priorities[i] = np.inf
    return priorities
